#include "behavior_planner/signal/mock_traffic_light_provider.hpp"
#include <yaml-cpp/yaml.h>
namespace behavior_planner { static TrafficLightState parse(const std::string&s){if(s=="RED")return TrafficLightState::RED;if(s=="YELLOW")return TrafficLightState::YELLOW;if(s=="GREEN")return TrafficLightState::GREEN;return TrafficLightState::UNKNOWN;} bool MockTrafficLightProvider::load(const std::string&p){try{auto y=YAML::LoadFile(p);fallback_=parse(y["default_state"].as<std::string>("GREEN"));if(y["traffic_lights"])for(auto it:y["traffic_lights"])states_[it.first.as<std::string>()]=parse(it.second.as<std::string>());return true;}catch(...){return false;}} TrafficLightState MockTrafficLightProvider::getState(const std::string&id)const{auto it=states_.find(id);return it==states_.end()?fallback_:it->second;} }
